// Restituisce la lista di tutti i progetti
const staticData = $getWorkflowStaticData('global');
const indice = staticData.indice_progetti || [];
const progetti = staticData.progetti || {};

// Restituisci sia l'indice che i dati completi
const risultato = indice.map(item => {
  const progetto = progetti[item.id];
  return {
    id: item.id,
    nome_evento: progetto?.brief?.nome_evento || item.nome_evento,
    cliente: progetto?.brief?.nome_cliente || item.cliente,
    azienda: progetto?.brief?.azienda || '',
    data_evento: progetto?.brief?.data_evento || '',
    data_creazione: item.data_creazione,
    stato: progetto?.stato || item.stato,
    numero_partecipanti: progetto?.brief?.numero_partecipanti || '',
    budget_totale: progetto?.brief?.budget_totale || '',
    citta: progetto?.brief?.citta || ''
  };
});

return { json: { progetti: risultato } };

// Restituisce il dettaglio di un singolo progetto
const staticData = $getWorkflowStaticData('global');
const progetti = staticData.progetti || {};
const progettoId = $input.first().json.params?.id || $input.first().json.query?.id;

if (!progettoId || !progetti[progettoId]) {
  return { json: { error: 'Progetto non trovato', id: progettoId } };
}

return { json: progetti[progettoId] };

// Aggiorna un progetto con i dati dell'event manager
// (costi reali, selezioni, note)
const staticData = $getWorkflowStaticData('global');
const progetti = staticData.progetti || {};
const input = $input.first().json.body || $input.first().json;

const progettoId = input.progetto_id;

if (!progettoId || !progetti[progettoId]) {
  return { json: { error: 'Progetto non trovato', id: progettoId } };
}

const progetto = progetti[progettoId];

// Aggiorna i campi modificabili dall'event manager
if (input.costi_reali) {
  progetto.costi_reali = { ...progetto.costi_reali, ...input.costi_reali };
}

if (input.selezioni_manager) {
  progetto.selezioni_manager = { ...progetto.selezioni_manager, ...input.selezioni_manager };
}

if (input.note_manager !== undefined) {
  progetto.note_manager = input.note_manager;
}

if (input.stato) {
  progetto.stato = input.stato;
}

// Aggiungi allo storico
progetto.storico.push({
  data: new Date().toISOString(),
  azione: input.azione_log || 'Progetto aggiornato dall\'event manager',
  utente: input.utente || 'event_manager'
});

// Salva
staticData.progetti[progettoId] = progetto;

// Aggiorna anche l'indice
if (staticData.indice_progetti) {
  const idx = staticData.indice_progetti.findIndex(p => p.id === progettoId);
  if (idx >= 0) {
    staticData.indice_progetti[idx].stato = progetto.stato;
  }
}

return { json: { success: true, progetto: progetto } };

// Prepara il prompt per QWEN per ricercare info su un fornitore/servizio
const input = $input.first().json.body || $input.first().json;

const query = input.query || '';
const citta = input.citta || '';

const prompt = `Sei un esperto event planner italiano. Cerca e fornisci informazioni dettagliate su: ${query}

Fornisci per ogni risultato trovato (massimo 5 risultati):
- Nome completo del fornitore/venue/servizio
- Descrizione breve
- Indirizzo o zona (se noto)
- Range di prezzo stimato
- Sito web (se noto)
- Punti di forza
- Contatti (telefono, email se noti)

Concentrati sulla zona di ${citta || 'Italia'}.
Rispondi SOLO con JSON valido:
{
  "risultati": [
    {
      "titolo": "Nome Fornitore",
      "descrizione": "Descrizione dettagliata...",
      "indirizzo": "Indirizzo/zona",
      "prezzo": "Range prezzo stimato",
      "sito_web": "url se noto",
      "punti_forza": ["punto1", "punto2"],
      "contatto": "info contatto"
    }
  ]
}`;

return { json: { prompt } };

