// Parsing risposta QWEN ricerca
const input = $input.first().json;
let risultati = [];

try {
  const content = input.choices[0].message.content;
  const parsed = typeof content === 'string' ? JSON.parse(content) : content;
  risultati = parsed.risultati || [];
} catch (e) {
  try {
    const content = input.choices[0].message.content;
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      risultati = parsed.risultati || [];
    }
  } catch (e2) {
    risultati = [{ titolo: 'Errore nella ricerca', descrizione: 'Non è stato possibile elaborare la risposta AI' }];
  }
}

return { json: { risultati } };
